-- 2026-06-24  Authoritative fuel_data — 12-month gallon report (220 stops x 12 months)
-- Source: gallon-report-all-12mo-20260624.csv (user-confirmed true & accurate).
-- Contributed = Aggregator + Fleet (verified). 'rack' is NOT touched on conflict so
-- any user-edited tax/freight config is preserved.
-- Schema: fuel_data(stop_id text, month text, gallons numeric, aggregators jsonb,
--                   fleets jsonb, rack jsonb, updated_at timestamptz, PK(stop_id,month))
-- Idempotent — re-runnable.

BEGIN;

ON CONFLICT (stop_id, month) DO UPDATE SET
  gallons     = EXCLUDED.gallons,
  aggregators = EXCLUDED.aggregators,
  fleets      = EXCLUDED.fleets,
  updated_at  = now();

COMMIT;

-- Verify: SELECT month, COUNT(*) stops, ROUND(SUM(gallons)) total_gal
--           FROM public.fuel_data WHERE month BETWEEN '2025-06' AND '2026-05'
--          GROUP BY month ORDER BY month;
-- Expected 12-mo grand total contributed gallons: 33529416.259